                Nullable = true,
            };

            Assert.Equal(typeof(string), PostgresNpgsqlTypeExtensions.ClrTypeFromNpgsqlParameter(parameter));
        }

        [Fact]
        public void CitextResultMapsToString()
        {
            var resultElement = new ModuleResultElement
            {
                Name = "testcitextout",
                StoreType = "citext",
                Nullable = true,
            };

            Assert.Equal(typeof(string), PostgresNpgsqlTypeExtensions.GetClrType(resultElement));
        }

        [Fact]
        public void ScaffolderSkipsUnsupportedRoutineAndReportsName()
        {
            var model = new RoutineModel
            {
                Errors = new List<string>(),
                Routines = new List<Routine>
                {
                    new Function
                    {
                        Schema = "dbo",
                        Name = "testrefcursor",
                        HasValidResultSet = true,
                        Parameters = new List<ModuleParameter>
                        {
                            new ModuleParameter
                            {
                                Name = "p_refcur",
                                StoreType = "refcursor",
                                Nullable = true,
                            },
                        },
                        Results = new List<List<ModuleResultElement>>
                        {
                            new List<ModuleResultElement>(),
                        },
                    },
                    new Function
                    {
                        Schema = "dbo",
                        Name = "testtext",
                        HasValidResultSet = true,
                        Parameters = new List<ModuleParameter>
                        {
                            new ModuleParameter
                            {
                                Name = "p_text",
                                StoreType = "text",
                                Nullable = true,
                            },
                        },
                        Results = new List<List<ModuleResultElement>>
                        {
                            new List<ModuleResultElement>
                            {
                                new ModuleResultElement
                                {
                                    Name = "testtext",
                                    StoreType = "text",
                                    Nullable = true,
                                },
                            },
                        },
                    },
                },
            };

            var errors = new List<string>();
            var scaffolder = new PostgresStoredProcedureScaffolder(new CSharpHelper(), new PostgresClrTypeMapper());
            var scaffolded = scaffolder.ScaffoldModel(
                model,
                new ModuleScaffolderOptions
                {
                    ContextDir = ".",
                    ContextName = "PgContext",
                    ContextNamespace = "Test.Context",
                    ModelNamespace = "Test.Models",
                    UseAsyncCalls = true,
                },
                new List<string>(),
                ref errors);

            Assert.Single(model.Routines);
            Assert.Equal("testtext", model.Routines[0].Name);
            Assert.Contains(errors, e => e.Contains("Unable to scaffold \"dbo\".\"testrefcursor\"", StringComparison.Ordinal) && e.Contains("p_refcur", StringComparison.Ordinal) && e.Contains("refcursor", StringComparison.Ordinal));
            Assert.Contains(scaffolded.AdditionalFiles, f => f.Path.EndsWith("TesttextResult.cs", StringComparison.OrdinalIgnoreCase));
            Assert.NotNull(scaffolded.ContextFile);
        }
    }
}

