                    }

                    Sb.AppendLine("}");
                }

                Sb.AppendLine("}");
                Sb.AppendLine();

                Sb.AppendLine($"{accessModifier} partial class {scaffolderOptions.ContextName}{FileNameSuffix} : I{scaffolderOptions.ContextName}{FileNameSuffix}");
